"""Доменная модель «модель от LLM-провайдера»: возможности и метаданные с API."""from __future__ import annotationsfrom dataclasses import asdict, dataclassfrom typing import Any@dataclassclass LLMModel:    """    Модель в представлении провайдера: идентификация, модальности входа/выхода,    фичи и контекст. Используется при получении списка с API до записи в реестр.    """    # Идентификация    provider: str    name: str    # Управление записью в реестре    can_update: bool = False  # только служебный флаг merge/boot; после ручной правки пользователя должен быть False    enabled: bool = True    # Вход    input_text: bool = False    input_image: bool = False    input_audio: bool = False    input_video: bool = False    # Выход    output_text: bool = False    output_image: bool = False    output_audio: bool = False    output_video: bool = False    # Фичи    chat: bool = False    function_calling: bool = False    structured_output: bool = False    reasoning: bool = False    # Контекст    context_window: int | None = None    price_input: float | None = None    price_output: float | None = None    # Метаданные (timestamp)    created: int = 0    def to_registry_record(self) -> dict[str, Any]:        """Преобразует модель в словарь записи реестра (для store.data)."""        return asdict(self)